import{_ as a}from"./chunks/fantu-cover.EHiDBquD.js";import{_ as r,o as t,c as o,ai as s}from"./chunks/framework.DyvBZb4W.js";const f=JSON.parse('{"title":"FanTu Character Mod","description":"","frontmatter":{},"headers":[],"relativePath":"en/mods/fantu-character/index.md","filePath":"en/mods/fantu-character/index.md","lastUpdated":1779029223000}'),n={name:"en/mods/fantu-character/index.md"};function i(c,e,l,h,d,p){return t(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="fantu-character-mod" tabindex="-1">FanTu Character Mod <a class="header-anchor" href="#fantu-character-mod" aria-label="Permalink to &quot;FanTu Character Mod&quot;">​</a></h1><p>FanTu is a custom character mod for Slay the Spire 2. Its first playable persona is Wen Dao Ke, while the mod itself is structured as an expandable framework for personas, appearances, packs, relics, and potions.</p><figure><img src="'+a+'" alt="FanTu Character Mod preview cover"><figcaption>Different packs each run. A smaller card pool, a new route through the Spire.</figcaption></figure><p>Current version: <code>v0.1.0</code><br> Release status: preview / early playable<br> Author: Jason Song<br> Type: custom character / randomized packs / multi-archetype deckbuilding<br> Gameplay impact: yes. It adds a new character, custom cards, packs, relics, potions, and deckbuilding rules.</p><h2 id="core-gameplay" tabindex="-1">Core Gameplay <a class="header-anchor" href="#core-gameplay" aria-label="Permalink to &quot;Core Gameplay&quot;">​</a></h2><p>FanTu is inspired by Packmaster from Slay the Spire 1. Packmaster&#39;s key idea is that a run does not draw from one fixed character card pool. Instead, several small themed packs are chosen at the start, and those packs form the card pool for that run. The available cards change from run to run, so deckbuilding changes with the pack combination.</p><p>FanTu brings that idea into Slay the Spire 2 as a custom character. The character keeps a base pack, then each run can add several archetype packs through random slots, three-choice random slots, or fixed pack choices. Those selected packs become the run&#39;s card pool, and the mod gives players ways to preview the run&#39;s themes and inspect the available cards during play.</p><h2 id="what-the-preview-is-about" tabindex="-1">What The Preview Is About <a class="header-anchor" href="#what-the-preview-is-about" aria-label="Permalink to &quot;What The Preview Is About&quot;">​</a></h2><ul><li><strong>Random but readable</strong>: each run can start from a different pack combination, while still showing the themes clearly before the deck takes shape.</li><li><strong>Combinable archetypes</strong>: cultivation, swordplay, formations, talismans, puppets, alchemy, gu arts, five elements, divination, ghost arts, body training, stars, and other packs point toward different resource loops and payoffs.</li><li><strong>Run-by-run choices</strong>: packs define what can appear, but rewards, upgrades, relics, potions, and routing still decide how the deck actually comes together.</li><li><strong>Expansion room</strong>: the long-term goal is for FanTu to become an expandable pack-based character framework, with more official and possibly third-party packs or appearances over time.</li></ul><h2 id="how-it-differs-from-a-normal-character" tabindex="-1">How It Differs From A Normal Character <a class="header-anchor" href="#how-it-differs-from-a-normal-character" aria-label="Permalink to &quot;How It Differs From A Normal Character&quot;">​</a></h2><p>Most characters have a stable full card pool. FanTu is closer to drawing several smaller pools at the start of each run, then building around the overlap between them. One run may lean into burst, another into defense loops, while another connects resources, marks, summons, potions, or long-term growth.</p><p>The fun is not memorizing one fixed answer. It is reading the starting pack mix, spotting which themes reinforce each other, deciding which weaknesses must be covered by rewards, and finding relic or potion links that make scattered pieces work together.</p><h2 id="current-status" tabindex="-1">Current Status <a class="header-anchor" href="#current-status" aria-label="Permalink to &quot;Current Status&quot;">​</a></h2><ul><li>This page is a preview first. Download links, demos, FAQ, and changelogs will be added as the public release plan becomes clearer.</li><li>The project is still in early tuning, so balance, card distribution, UI, and art may continue to change.</li><li>Requires <code>BaseLib</code>.</li></ul><h2 id="links" tabindex="-1">Links <a class="header-anchor" href="#links" aria-label="Permalink to &quot;Links&quot;">​</a></h2><ul><li>Back to <a href="/jasonsong-games/en/mods/">All Mods</a></li></ul>',16)])])}const b=r(n,[["render",i]]);export{f as __pageData,b as default};
